        offset += (size_t)ret;

        for (int i = 0; i < label_count; ++i) {
            ret = snprintf(
                tmp + offset,
                required_len + 1 - offset,
                "%s=\"%s\"",
                label_keys[i],
                label_values[i]
            );
            if (ret < 0 || (size_t)ret >= (required_len + 1 - offset)) {
                free(tmp);
                return -1;
            }
